import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Chip,
  IconButton,
  Tooltip,
  TextField,
  InputAdornment,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogContentText,
  DialogActions,
  LinearProgress,
  Tabs,
  Tab,
  Alert,
  Card,
  CardContent,
  Grid,
  LinearProgress as MuiLinearProgress,
} from '@mui/material';
import {
  Add,
  Search,
  Edit,
  Delete,
  Inventory,
  Refresh,
  Warning,
  CheckCircle,
  Category,
  LocalOffer,
  Straighten,
  TrendingUp,
  TrendingDown,
  Visibility,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { itemService } from '../../services/itemService';

const ItemList = () => {
  const navigate = useNavigate();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [totalElements, setTotalElements] = useState(0);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [tabValue, setTabValue] = useState(0);
  const [error, setError] = useState('');
  const [searchTimeout, setSearchTimeout] = useState(null);
  const [lowStockItems, setLowStockItems] = useState([]);

  useEffect(() => {
    fetchItems();
  }, [page, rowsPerPage]);

  const fetchItems = async () => {
    try {
      setLoading(true);
      setError('');
      const data = await itemService.getAll(page, rowsPerPage, search);
      setItems(data.content || []);
      setTotalElements(data.totalElements || 0);
      console.log('📦 Items loaded:', data.content?.length || 0);
    } catch (error) {
      console.error('❌ Fetch error:', error);
      setError('Failed to fetch items');
      toast.error('Failed to fetch items');
    } finally {
      setLoading(false);
    }
  };

  const fetchLowStockItems = async () => {
    try {
      const data = await itemService.getLowStock();
      setLowStockItems(data || []);
    } catch (error) {
      console.error('Error fetching low stock items:', error);
    }
  };

  const handleSearch = (value) => {
    setSearch(value);
    setPage(0);
    
    if (searchTimeout) clearTimeout(searchTimeout);
    const timeout = setTimeout(() => {
      fetchItems();
    }, 500);
    setSearchTimeout(timeout);
  };

  const handleDelete = async () => {
    try {
      setLoading(true);
      await itemService.delete(selectedItem.id);
      toast.success(`Item "${selectedItem.name}" deleted successfully`);
      setDeleteDialogOpen(false);
      setSelectedItem(null);
      await fetchItems();
      await fetchLowStockItems();
    } catch (error) {
      console.error('Delete error:', error);
      toast.error(error.response?.data?.error || 'Failed to delete item');
    } finally {
      setLoading(false);
    }
  };

  const openDeleteDialog = (item) => {
    setSelectedItem(item);
    setDeleteDialogOpen(true);
  };

  const getStockStatus = (item) => {
    if (item.currentStock <= 0) {
      return { label: 'Out of Stock', color: 'error', icon: <Warning /> };
    }
    if (item.currentStock <= item.reorderLevel) {
      return { label: 'Low Stock', color: 'warning', icon: <Warning /> };
    }
    if (item.currentStock <= item.minStockLevel) {
      return { label: 'Critical', color: 'warning', icon: <Warning /> };
    }
    return { label: 'In Stock', color: 'success', icon: <CheckCircle /> };
  };

  const getStockLevelColor = (currentStock, minLevel, maxLevel) => {
    const percentage = (currentStock / maxLevel) * 100;
    if (percentage <= 25) return 'error';
    if (percentage <= 50) return 'warning';
    return 'success';
  };

  const isNewItem = (createdAt) => {
    if (!createdAt) return false;
    const created = new Date(createdAt);
    const now = new Date();
    const diffHours = (now - created) / (1000 * 60 * 60);
    return diffHours < 24;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-IN', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const formatCurrency = (amount) => {
    if (!amount) return '₹0.00';
    return `₹${amount.toFixed(2)}`;
  };

  const handleTabChange = (event, newValue) => {
    setTabValue(newValue);
    if (newValue === 1) {
      fetchLowStockItems();
    } else {
      fetchItems();
    }
  };

  const renderStockBar = (item) => {
    const percentage = Math.min((item.currentStock / item.maxStockLevel) * 100, 100);
    return (
      <Box sx={{ width: '100%', minWidth: 100 }}>
        <MuiLinearProgress
          variant="determinate"
          value={percentage}
          color={getStockLevelColor(item.currentStock, item.minStockLevel, item.maxStockLevel)}
          sx={{ height: 8, borderRadius: 4 }}
        />
        <Typography variant="caption" color="textSecondary">
          {item.currentStock} / {item.maxStockLevel}
        </Typography>
      </Box>
    );
  };

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Items
          </Typography>
          <Typography variant="body2" color="textSecondary">
            Manage your product inventory
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<Add />}
          onClick={() => navigate('/items/new')}
          sx={{ borderRadius: 2 }}
        >
          Add Item
        </Button>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Tabs value={tabValue} onChange={handleTabChange} sx={{ mb: 2 }}>
        <Tab label="All Items" icon={<Inventory />} iconPosition="start" />
        <Tab label="Low Stock" icon={<Warning />} iconPosition="start" />
        <Tab label="Brands" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/brands')} />
        <Tab label="Groups" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/groups')} />
        <Tab label="Sections" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/sections')} />
        <Tab label="Units" icon={<Straighten />} iconPosition="start" onClick={() => navigate('/items/units')} />
        <Tab label="Taxes" icon={<LocalOffer />} iconPosition="start" onClick={() => navigate('/items/taxes')} />
      </Tabs>

      <Paper sx={{ p: 2, borderRadius: 2 }}>
        <Box display="flex" gap={2} mb={2} flexWrap="wrap">
          <TextField
            placeholder="Search items by name or code..."
            value={search}
            onChange={(e) => handleSearch(e.target.value)}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Search />
                </InputAdornment>
              ),
            }}
            sx={{ flexGrow: 1, minWidth: 200 }}
            size="small"
          />
          <Button
            variant="outlined"
            startIcon={<Refresh />}
            onClick={fetchItems}
            size="medium"
          >
            Refresh
          </Button>
        </Box>

        {loading ? (
          <Box sx={{ width: '100%', py: 4 }}>
            <LinearProgress />
            <Typography textAlign="center" sx={{ mt: 2 }} color="textSecondary">
              Loading items...
            </Typography>
          </Box>
        ) : (
          <>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                    <TableCell>#</TableCell>
                    <TableCell>Code</TableCell>
                    <TableCell>Name</TableCell>
                    <TableCell>Brand</TableCell>
                    <TableCell>Group</TableCell>
                    <TableCell align="right">Price</TableCell>
                    <TableCell>Stock</TableCell>
                    <TableCell>Status</TableCell>
                    <TableCell>Created At</TableCell>
                    <TableCell align="center">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {items.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={10} align="center" sx={{ py: 4 }}>
                        <Typography variant="body1" color="textSecondary">
                          {tabValue === 1 ? 'No low stock items found' : 'No items found'}
                        </Typography>
                      </TableCell>
                    </TableRow>
                  ) : (
                    items.map((item, index) => {
                      const stockStatus = getStockStatus(item);
                      return (
                        <TableRow key={item.id} hover>
                          <TableCell>{page * rowsPerPage + index + 1}</TableCell>
                          <TableCell>
                            <Typography variant="body2" fontWeight={500}>
                              {item.code}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            <Box display="flex" alignItems="center" gap={1}>
                              <Inventory sx={{ color: '#1976d2', fontSize: 20 }} />
                              <Box>
                                <Typography fontWeight={500}>{item.name}</Typography>
                                {isNewItem(item.createdAt) && (
                                  <Chip 
                                    label="NEW" 
                                    color="primary" 
                                    size="small" 
                                    sx={{ ml: 1, height: 18, fontSize: '0.6rem' }}
                                  />
                                )}
                              </Box>
                            </Box>
                          </TableCell>
                          <TableCell>{item.brandName || '-'}</TableCell>
                          <TableCell>{item.groupName || '-'}</TableCell>
                          <TableCell align="right">
                            <Typography variant="body2" fontWeight={500}>
                              {formatCurrency(item.sellingPrice)}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            {renderStockBar(item)}
                          </TableCell>
                          <TableCell>
                            <Chip
                              icon={stockStatus.icon}
                              label={stockStatus.label}
                              color={stockStatus.color}
                              size="small"
                              sx={{ fontWeight: 500 }}
                            />
                          </TableCell>
                          <TableCell>
                            <Typography variant="caption" color="textSecondary">
                              {formatDate(item.createdAt)}
                            </Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Tooltip title="View">
                              <IconButton
                                size="small"
                                color="info"
                                onClick={() => navigate(`/items/${item.id}`)}
                              >
                                <Visibility />
                              </IconButton>
                            </Tooltip>
                            <Tooltip title="Edit">
                              <IconButton
                                size="small"
                                color="primary"
                                onClick={() => navigate(`/items/edit/${item.id}`)}
                              >
                                <Edit />
                              </IconButton>
                            </Tooltip>
                            <Tooltip title="Delete">
                              <IconButton
                                size="small"
                                color="error"
                                onClick={() => openDeleteDialog(item)}
                              >
                                <Delete />
                              </IconButton>
                            </Tooltip>
                          </TableCell>
                        </TableRow>
                      );
                    })
                  )}
                </TableBody>
              </Table>
            </TableContainer>

            <TablePagination
              rowsPerPageOptions={[5, 10, 25, 50]}
              component="div"
              count={totalElements}
              rowsPerPage={rowsPerPage}
              page={page}
              onPageChange={(e, newPage) => setPage(newPage)}
              onRowsPerPageChange={(e) => {
                setRowsPerPage(parseInt(e.target.value, 10));
                setPage(0);
              }}
            />
          </>
        )}
      </Paper>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onClose={() => setDeleteDialogOpen(false)}>
        <DialogTitle>Delete Item</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Are you sure you want to delete item "{selectedItem?.name}"?
            This action cannot be undone.
          </DialogContentText>
          <Box mt={2} p={2} bgcolor="#f5f7fa" borderRadius={1}>
            <Typography variant="body2">
              <strong>Code:</strong> {selectedItem?.code}
            </Typography>
            <Typography variant="body2">
              <strong>Current Stock:</strong> {selectedItem?.currentStock}
            </Typography>
            <Typography variant="body2">
              <strong>Price:</strong> {formatCurrency(selectedItem?.sellingPrice)}
            </Typography>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteDialogOpen(false)}>Cancel</Button>
          <Button 
            onClick={handleDelete} 
            color="error" 
            variant="contained"
            startIcon={<Delete />}
          >
            Delete
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default ItemList;
